Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: injectable mock handler
    private static HttpClient CreateMockClient(
        HttpStatusCode status, string content, TimeSpan? delay = null)
    {
        var handler = new MockHttpMessageHandler(status, content, delay);
        return new HttpClient(handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnErrorStatus()
    {
        using var client = CreateMockClient(HttpStatusCode.InternalServerError, "");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledBeforeCall()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // already cancelled

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        // Handler delays 5s; we cancel after 50ms
        using var client = CreateMockClient(
            HttpStatusCode.OK, "slow", delay: TimeSpan.FromSeconds(5));
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // guard: fail fast if something hangs
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        using var client = CreateMockClient(
            HttpStatusCode.OK, "fast", delay: TimeSpan.FromMilliseconds(100));
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }
}

// Reusable mock handler — no external dependencies needed
public class MockHttpMessageHandler : HttpMessageHandler
{
    private readonly HttpStatusCode _status;
    private readonly string _content;
    private readonly TimeSpan _delay;

    public MockHttpMessageHandler(
        HttpStatusCode status, string content, TimeSpan? delay = null)
    {
        _status = status;
        _content = content;
        _delay = delay ?? TimeSpan.Zero;
    }

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        if (_delay > TimeSpan.Zero)
            await Task.Delay(_delay, cancellationToken);

        return new HttpResponseMessage(_status)
        {
            Content = new StringContent(_content)
        };
    }
}
```

**Key patterns used:**

| Technique | Purpose |
|---|---|
| `MockHttpMessageHandler` | Avoids real HTTP calls; controls status, content, and latency |
| `CancellationTokenSource(delay)` | Simulates a timeout that fires *during* a slow request |
| Pre-cancelled `cts.Cancel()` | Verifies the token is checked before the request starts |
| `[Timeout(3000)]` | MSTest-level safety net so a hung test fails instead of blocking CI |
| `Assert.ThrowsExceptionAsync` | Properly awaits and asserts async exceptions |

**One gotcha:** `[Timeout]` in MSTest runs the test on a separate thread, which can mask `SynchronizationContext` bugs. For pure timeout enforcement without thread-switching, prefer the `CancellationTokenSource(TimeSpan)` pattern inside the test body itself.
